#include <bits/stdc++.h>
using namespace std;

const int N=1010;

struct Edge{
    int to;
    long long val;
    bool operator<(Edge y)const{
        return val>y.val;
    }
};

int n,m,k,cnt[N],dis[N];
vector<Edge> g[N],r[N];
bool b[N];

void Dijkstra(){
    memset(dis,0x3f,sizeof(dis));
    priority_queue<Edge> q;
    dis[n]=0;
    q.push({n,1ll*dis[n]});
    while(q.size()){
        while(q.size() && b[q.top().to])
            q.pop();
        if(q.empty())
            break;
        int x=q.top().to;
        q.pop(),b[x]=1;
        for(Edge y:r[x])
            if(dis[y.to]>dis[x]+y.val){
                dis[y.to]=dis[x]+y.val;
                q.push({y.to,1ll*dis[y.to]});
            }
    }
}

void Astar(){
    priority_queue<Edge> q;
    q.push({1,dis[1]});
    while(q.size()){
        int x=q.top().to;
        long long val=q.top().val-dis[x];
        q.pop(),cnt[x]++;
        if(cnt[x]>k)
            continue;
        if(x==n)
            printf("%lld\n",val);
        for(Edge y:g[x])
            q.push({y.to,dis[y.to]+val+y.val});
    }
    while(cnt[n]<k){
        puts("-1");
        cnt[n]++;
    }
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        if(u>v)
            swap(u,v);
        g[u].push_back({v,1ll*w});
        r[v].push_back({u,1ll*w});
    }
    Dijkstra();
    Astar();
    return 0;
}
